import React, {useState} from 'react';
import {STRINGS} from "../../constants/strings";

function NewContact(props){
    const {userData} = props;
    const [inviteCode, setInviteCode] = useState("");

    const handleInviteCode = (event) => {
        setInviteCode(event.target.value);
    }
    console.log(inviteCode);
    return (
        <div className="newContact-container">
            {userData && (
                <div className="newContact">
                    <h4 className="newContact-title">{STRINGS[userData.language].NewContact}</h4>
                    {/*<h5 className="newContact-invitation-code">{STRINGS[userData.language].InvitationCode}</h5>*/}
                    <form
                        className="newContactForm"
                        onSubmit={handleInviteCode}
                    >
                        <input
                            className="newContact-search"
                            type="text"
                            placeholder={STRINGS[userData.language].InvitationCode}
                            value={inviteCode}
                            onChange={handleInviteCode}
                        ><label><i className="bi bi-search"></i></label></input>
                    </form>
                </div>
            )}
        </div>
    );
}

export default NewContact;
